const cursor=document.getElementById('cursor');const ring=document.getElementById('cursorRing');let mx=0,my=0,rx=0,ry=0;document.addEventListener('mousemove',e=>{mx=e.clientX;my=e.clientY;cursor.style.left=mx+'px';cursor.style.top=my+'px';});function animRing(){rx+=(mx-rx)*0.12;ry+=(my-ry)*0.12;ring.style.left=rx+'px';ring.style.top=ry+'px';requestAnimationFrame(animRing);}animRing();document.querySelectorAll('a,button,.cmd-card,.qs-step,.sec-item,.case-card,.arch-pill').forEach(el=>{el.addEventListener('mouseenter',()=>{cursor.style.width='18px';cursor.style.height='18px';ring.style.width='50px';ring.style.height='50px';});el.addEventListener('mouseleave',()=>{cursor.style.width='10px';cursor.style.height='10px';ring.style.width='36px';ring.style.height='36px';});});const revealEls=document.querySelectorAll('.reveal');const observer=new IntersectionObserver(entries=>{entries.forEach(e=>{if(e.isIntersecting){e.target.classList.add('visible');observer.unobserve(e.target);}});},{threshold:0.1,rootMargin:'0px 0px-40px 0px'});revealEls.forEach((el,i)=>{el.style.transitionDelay=`${(i % 4)*0.07}s`;observer.observe(el);});const termLines=document.querySelectorAll('#termBody > div,#termBody > br');termLines.forEach((line,i)=>{line.style.opacity='0';line.style.transition='opacity 0.25s';setTimeout(()=>{line.style.opacity='1';},800+i*160);});document.querySelectorAll('.arch-pill').forEach(pill=>{pill.addEventListener('mouseenter',()=>{pill.style.boxShadow='0 0 12px rgba(91,255,192,0.3)';});pill.addEventListener('mouseleave',()=>{pill.style.boxShadow='';});});const statVals=document.querySelectorAll('.stat-val');const statObs=new IntersectionObserver(entries=>{entries.forEach(e=>{if(!e.isIntersecting)return;const el=e.target;const target=parseInt(el.textContent);if(isNaN(target))return;let start=0;const step=Math.ceil(target/30);const interval=setInterval(()=>{start=Math.min(start+step,target);el.textContent=start;if(start >=target)clearInterval(interval);},40);statObs.unobserve(el);});},{threshold:0.5});statVals.forEach(v=> statObs.observe(v));